function filterSlots(slots, specificTime = null, timeGapMinutes = 60, hourlyIntervalMinutes = 60, maxSlots = 3) {
    if (!slots || !Array.isArray(slots) || slots.length === 0) {
        return [];
    }

    // If fewer than 5 slots, return all without filtering
    if (slots.length < 5) {
        return slots;
    }

    // Case 1: Filter around specific time    
    if (specificTime) {
        const targetTime = parseTimeString(specificTime);
        if (targetTime) {
            const targetTotalMinutes = targetTime.hour * 60 + targetTime.minute;
            // Sort all slots by proximity to the target time and return the closest maxSlots
            const sorted = [...slots].sort((a, b) => {
                const getMinutes = slot => {
                    const t = new Date(slot.start_date).toLocaleString("en-US", {
                        timeZone: timezone, hour12: false, hour: '2-digit', minute: '2-digit'
                    });
                    const [h, m] = t.split(':').map(Number);
                    return h * 60 + m;
                };
                return Math.abs(getMinutes(a) - targetTotalMinutes) - Math.abs(getMinutes(b) - targetTotalMinutes);
            });
            // Return closest maxSlots, re-sorted by time ascending
            const closest = sorted.slice(0, maxSlots);
            closest.sort((a, b) => new Date(a.start_date).getTime() - new Date(b.start_date).getTime());
            return closest;
        }
    }

    // Case 2: Filter by hourly intervals
    return filterByHourlyInterval(slots, hourlyIntervalMinutes);
}

/**
 * Filter slots around a specific time with configurable gap
 */
function filterAroundSpecificTime(slots, targetTime, gapMinutes) {

   const filteredSlots = slots.filter(slot => {
        const slotTime = new Date(slot.start_date);

        // Convert UTC time to local timezone
        const localTimeString = slotTime.toLocaleString("en-US", { 
            timeZone: timezone,
            hour12: false,
            hour: '2-digit',
            minute: '2-digit'
        });

        // Parse the local time string "HH:MM"
        const [slotHour, slotMinute] = localTimeString.split(':').map(Number);

        // Convert times to minutes for easier comparison
        const targetTotalMinutes = targetTime.hour * 60 + targetTime.minute;
        const slotTotalMinutes = slotHour * 60 + slotMinute;

        // Simple time difference check (no cross-day logic needed)
        const timeDifference = Math.abs(slotTotalMinutes - targetTotalMinutes);

        return timeDifference <= gapMinutes;
    });

    // If no slots found after filtering, return original slots
    return filteredSlots.length > 0 ? filteredSlots : slots;
}

function filterByHourlyInterval(slots, intervalMinutes, targetTime = null) {
    if (slots.length === 0) return [];

    // Group slots by date to process each day independently
    const slotsByDate = {};

    slots.forEach(slot => {
        const slotTime = new Date(slot.start_date);
        const dateKey = slotTime.toLocaleString("en-US", {
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit'
        });

        if (!slotsByDate[dateKey]) {
            slotsByDate[dateKey] = [];
        }
        slotsByDate[dateKey].push(slot);
    });

    const filteredSlots = [];

    // Process each date independently
    Object.keys(slotsByDate).forEach(dateKey => {
        const dateSlotsGroup = slotsByDate[dateKey];

        // Group slots into buckets aligned to clock hours (or intervalMinutes boundaries)
        // Key: which interval bucket this slot falls into
        const buckets = {};

        dateSlotsGroup.forEach(slot => {
            const slotTime = new Date(slot.start_date);
            const localTimeString = slotTime.toLocaleString("en-US", {
                timeZone: timezone,
                hour12: false,
                hour: '2-digit',
                minute: '2-digit'
            });

            const [slotHour, slotMinute] = localTimeString.split(':').map(Number);
            const slotTotalMinutes = slotHour * 60 + slotMinute;

            // Align bucket to clock-based intervalMinutes boundaries (e.g. 0, 60, 120, ...)
            const bucketKey = Math.floor(slotTotalMinutes / intervalMinutes);

            if (!buckets[bucketKey]) {
                buckets[bucketKey] = [];
            }
            buckets[bucketKey].push({ slot, slotTotalMinutes });
        });

        // From each bucket pick the slot closest to the targetTime (if given) or the first slot
        Object.keys(buckets).sort((a, b) => Number(a) - Number(b)).forEach(bucketKey => {
            const entries = buckets[bucketKey];
            let chosen;
            if (targetTime) {
                const targetTotalMinutes = targetTime.hour * 60 + targetTime.minute;
                chosen = entries.reduce((best, entry) =>
                    Math.abs(entry.slotTotalMinutes - targetTotalMinutes) <
                    Math.abs(best.slotTotalMinutes - targetTotalMinutes) ? entry : best
                );
            } else {
                chosen = entries[0];
            }
            filteredSlots.push(chosen.slot);
        });
    });

    // If no filtered slots found, return original slots
    return filteredSlots.length > 0 ? filteredSlots : slots;
}

/**
 * Parse time string to hour and minute
 */
function parseTimeString(timeStr) {
    // Handle formats like "3:15 PM", "15:15", "3:15"
    const time12HourMatch = timeStr.match(/(\d{1,2}):(\d{2})\s*(AM|PM)/i);
    const time24HourMatch = timeStr.match(/(\d{1,2}):(\d{2})/);

    if (time12HourMatch) {
        let hour = parseInt(time12HourMatch[1]);
        const minute = parseInt(time12HourMatch[2]);
        const period = time12HourMatch[3].toUpperCase();

        if (period === 'PM' && hour !== 12) hour += 12;
        if (period === 'AM' && hour === 12) hour = 0;

        return { hour, minute };
    } else if (time24HourMatch) {
        const hour = parseInt(time24HourMatch[1]);
        const minute = parseInt(time24HourMatch[2]);
        return { hour, minute };
    }

    return null;
}

/**
 * Analyze slot availability and return a workflow status message
 */
function analyzeSlotAvailability(slots) {
    const getHour = slot => {
        const timeStr = slot.time;
        const match = timeStr.match(/(\d{1,2}):\d{2}\s*(AM|PM)/i);
        if (!match) return 0;
        let hour = parseInt(match[1]);
        const period = match[2].toUpperCase();
        if (period === 'PM' && hour !== 12) hour += 12;
        if (period === 'AM' && hour === 12) hour = 0;
        return hour;
    };

    if (slots.length === 0) {
        return { status: "Unfortunately, no available slots based on current user preference.", slotsIdentified: false };
    }

    const morningSlots = slots.filter(slot => getHour(slot) < 12);
    const afternoonSlots = slots.filter(slot => getHour(slot) >= 12);
    const date = slots[0].date;

    const requestedDateRaw = Context.getVariable("start_date");
    const requestedDate = new Date(requestedDateRaw).toLocaleDateString("en-US", {
        month: 'long', day: 'numeric', year: 'numeric'
    }).replace(',', '');
    const isDateMismatch = requestedDate !== date;
    const prefix = isDateMismatch
        ? `I see ${requestedDate} is fully booked, but we have `
        : `We have `;

    if (morningSlots.length > 6 && afternoonSlots.length === 0) {
        return { status: `${prefix}plenty availability on ${date} ONLY in the morning. Which time do you prefer in the morning?`, slotsIdentified: false };
    } else if (afternoonSlots.length > 6 && morningSlots.length === 0) {
        return { status: `${prefix}plenty availability on ${date} ONLY in the afternoon. Which time do you prefer in the afternoon?`, slotsIdentified: false };
    } else if (slots.length > 6) {
        return { status: `${prefix}plenty availability on ${date} — in the morning and afternoon. Which time do you prefer?`, slotsIdentified: false };
    } else {
        return { status: `${prefix}availability on ${date} at the following times: ${slots.map(s => s.time).join(', ')}. Which time works best for you?`, slotsIdentified: true };
    }
}

