 * Returns only the location info of the latest visit if lab/glucose test exists
 */
function getLatestLabOrGlucoseTestLocation(encountersData) {
    const encounters = encountersData.encounters || [];

    // Filter encounters for lab tests or glucose tests
    const labOrGlucoseTests = encounters.filter(encounter => {
        const type = encounter.type.toLowerCase();
        return type.includes('lab') || type.includes('glucose');
    });

    if (labOrGlucoseTests.length === 0) {
        return {
            hasLabOrGlucoseTest: false,
            location_id: null,
            location: null
        };
    }

    // Sort by date_time to get the latest one
    labOrGlucoseTests.sort((a, b) => {
        return new Date(b.date_time).getTime() - new Date(a.date_time).getTime();
    });

    const latestTest = labOrGlucoseTests[0];

    return {
        hasLabOrGlucoseTest: true,
        location_id: latestTest.location_id,
        location: latestTest.location
    };
}
