/**
 * Generate today's date based on the provided timezone
 * @param {string} timezone - The timezone string (e.g., 'America/New_York', 'Europe/London')
 * @returns {Object} Object containing various date formats
 */
function getTodayByTimezone(timezone) {
    try {
        // Create a new Date object for current time
        const now = new Date();

        // Get the date string in the specified timezone (simpler approach)
        const dateString = now.toLocaleDateString("en-US", { timeZone: timezone });

        // Parse the date string (format: MM/DD/YYYY)
        const dateParts = dateString.split('/');
        const month = dateParts[0].padStart(2, '0');
        const day = dateParts[1].padStart(2, '0');
        const year = dateParts[2];

        // Get weekday name
        const weekdayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        const localDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
        const weekday = weekdayNames[localDate.getDay()];

        return {
            // Standard formats
            iso: `${year}-${month}-${day}`,
            us: `${month}/${day}/${year}`,
            readable: `${weekday}, ${month}/${day}/${year}`,

            // Individual components
            year: parseInt(year),
            month: parseInt(month),
            day: parseInt(day),
            weekday: weekday,

            // Timezone info
            timezone: timezone
        };

    } catch (error) {
        throw new Error(`Invalid timezone: ${timezone}. Error: ${error.message}`);
    }
}

