/**
 * Validates if an appointment can be cancelled based on its date and service type
 * @param {string} appointmentId - The ID of the appointment to validate
 * @param {Array} appointmentsList - The list of appointments to search in
 * @returns {Object} - Object with canCancel status and reason
 */
function validateAppointmentCancellation(appointmentId, appointmentsList) {

    // Find the appointment by ID
    const appointment = appointmentsList.find(apt => apt.id === appointmentId);

    // If appointment not found
    if (!appointment) {
        return {
            canCancel: false,
            reason: "Appointment not found"
        };
    }

    // Check if the appointment is scheduled for today
    const timezone = Context.getVariable("timezone");
    const appointmentDate = new Date(appointment.date_time);
    // Convert today's date to local timezone for proper comparison
    const today = new Date();
    const todayString = today.toLocaleDateString("en-CA", { 
        timeZone: timezone 
    });

    // Convert both dates to YYYY-MM-DD format for comparison
    const appointmentDateString = appointmentDate.toLocaleDateString("en-CA");
    if (todayString === appointmentDateString) {
        return {
            canCancel: false,
            reason: "Error: Appointments for today cannot be cancelled"
        };
    }

    // If all checks pass, the appointment can be cancelled
    return {
        canCancel: true,
        reason: "Appointment is eligible for cancellation"
    };
}

